insert into public.routines (id, name, duration_min, group_name, intensity, when_to_do, why_it_works, sort_order) values
  ($q$quick-hip-reset$q$, $q$Quick Hip Reset$q$, 10, $q$hip_mobility$q$, $q$dynamic$q$, $q$Daily / anytime. Use as a morning greaser, pre-work, or when you’ve been sitting 3+ hours. No CNS cost — do it daily.$q$, $q$Hits rotation, flexion, abduction in under 10 min. Nothing loaded, nothing held long — pure movement prep.$q$, 0),
  ($q$deep-90-90-focus$q$, $q$Deep 90/90 Focus$q$, 25, $q$hip_mobility$q$, $q$deep$q$, $q$Rest day evening. Your weakest test — goes hard on hip rotation and nothing else.$q$, $q$Passive hold + active contract-relax (the lift-offs) is the PNF approach that actually changes ROM. Don’t skip the active reps.$q$, 1),
  ($q$external-rotation-deep-dive$q$, $q$External Rotation Deep Dive$q$, 30, $q$hip_mobility$q$, $q$deep$q$, $q$Rest day evening. External rotation = roundhouse kick height + wide stance. Your kick power session.$q$, $q$Every position here forces external rotation under different tensions. The torso rotation over 90/90 is the carryover to actually kicking.$q$, 2),
  ($q$internal-rotation-shin-box$q$, $q$Internal Rotation & Shin Box$q$, 20, $q$hip_mobility$q$, $q$medium$q$, $q$The sneaky one — gets ignored, causes low-back compensation. Do this 1x/week minimum.$q$, $q$The shin box is the single best drill for hip rotation you don’t already use. Flow both directions — don’t skip the “weaker” side.$q$, 3),
  ($q$post-ride-hip-flush$q$, $q$Post-Ride Hip Flush$q$, 15, $q$hip_mobility$q$, $q$light$q$, $q$Saturday night after Ténéré/Beta. Moto riding jacks up hip flexors, glute meds, and low back — this is the specific decompression.$q$, $q$Enduro + adventure riding loads your flexors despite the "pass" test — the riding position shortens them for hours. Couch stretch undoes it. Legs-up-the-wall flushes pooled blood after a long day.$q$, 4),
  ($q$hamstring-ladder$q$, $q$Hamstring Ladder$q$, 25, $q$legs$q$, $q$deep$q$, $q$Rest day or post-Muay Thai. Your #2 weak point and direct limiter to kick height — hits hamstrings from 4 different angles.$q$, $q$Supine (safest, deepest) + seated (stretches belly of muscle) + standing (functional). PNF at the end is what breaks the plateau.$q$, 5),
  ($q$adductor-groin-opener$q$, $q$Adductor / Groin Opener$q$, 25, $q$legs$q$, $q$deep$q$, $q$Your #3 priority. Don’t go crazy — adductors are injury-prone when over-stretched.$q$, $q$Graded frog (light → deeper) is safer than diving into max depth. Cossacks and wide squat hit dynamic range under load.$q$, 6),
  ($q$couch-stretch-quad-chain$q$, $q$Couch Stretch + Quad Chain$q$, 20, $q$legs$q$, $q$medium$q$, $q$Post-lift, or day after squats. You pass hip flexors but lifting heavy keeps them tight anyway.$q$, $q$Couch stretch is the king for quads + hip flexors in one. Post-squat it prevents gradual shortening that would eventually fail your hip flexor test.$q$, 7),
  ($q$calves-ankles-feet$q$, $q$Calves, Ankles & Feet$q$, 15, $q$legs$q$, $q$light$q$, $q$Muay Thai footwork, surfing pop-ups, enduro pegs — all ankle/calf dependent. This session gets ignored and it’s a common kick-power leak.$q$, $q$Teep kick power starts at the calf/ankle. Poor dorsiflexion = stunted teep chamber. Soleus work especially — most people only do straight-leg calf stretches.$q$, 8),
  ($q$full-lower-body-evening-flow$q$, $q$Full Lower Body Evening Flow$q$, 35, $q$legs$q$, $q$deep$q$, $q$Monday or Wednesday evening. This is your main session — all three weak points hit in one. Do 2–3x/week and actual progress happens.$q$, $q$The engine. Hip rotation + hamstrings + adductors in one deliberate sequence. Never the day before or day of heavy deadlifts/squats.$q$, 9),
  ($q$moto-rider-neck-forearms$q$, $q$Moto Rider Neck & Forearms$q$, 12, $q$upper_body$q$, $q$light$q$, $q$After any ride >1 hour. Specific to Ténéré (long adventure) and Beta (arm pump on tight enduro).$q$, $q$Helmet neck fatigue is neck extensor + upper trap dominance — this decompresses it. Forearm pump recovery comes from stretching the exact muscle groups you burned.$q$, 10),
  ($q$thoracic-shoulder-opener$q$, $q$Thoracic & Shoulder Opener$q$, 15, $q$upper_body$q$, $q$medium$q$, $q$2x/week, ideally before upper lift or surf. Lets you paddle without grinding low back, press deep with healthy shoulders, clinch cleaner.$q$, $q$T-spine extension is where surfing, overhead pressing, and paddle stroke all live. Foam roller extensions + wall angels actually changes posture over a few weeks.$q$, 11),
  ($q$post-lift-upper-flush$q$, $q$Post-Lift Upper Flush$q$, 15, $q$upper_body$q$, $q$light$q$, $q$After a bench/row/press session. Quick decompression, nothing deep. Keep pre-sleep if you lifted evening.$q$, $q$Pec + lat + delt are the 3 muscles you just pumped up and shortened. Hitting all three post-workout keeps shoulder position from drifting forward over years.$q$, 12),
  ($q$morning-full-body-wake-up$q$, $q$Morning Full Body Wake-Up$q$, 12, $q$full_body$q$, $q$dynamic$q$, $q$Daily. Zero CNS cost — do it on the floor next to your bed. No holds over 30s.$q$, $q$Wakes up every joint without any deep stretch. Best use: morning after enduro or heavy leg day, when everything feels crunchy but you need to move.$q$, 13),
  ($q$pre-muay-thai-dynamic-warmup$q$, $q$Pre-Muay Thai Dynamic Warmup$q$, 15, $q$full_body$q$, $q$dynamic$q$, $q$Before Muay Thai class. Dynamic only — no deep static holds, which would reduce power output for kicks.$q$, $q$Hits every joint, raises core temp, primes hip rotators without killing power. Shadow kicks at the end are what bridges warmup to actual Muay Thai.$q$, 14),
  ($q$kb-foundation-builder$q$, $q$KB Foundation Builder$q$, 40, $q$kb_only$q$, $q$medium$q$, $q$Default KB session. 2x/week if KB is your only lift, 1x/week if you also gym. The bread-and-butter day.$q$, $q$Hits the four KB pillars — hinge (swing), squat (goblet), press, row — at moderate volume. Builds the patterns before you load them heavy.$q$, 15),
  ($q$heavy-double-kb-strength$q$, $q$Heavy Double KB Strength$q$, 50, $q$kb_only$q$, $q$deep$q$, $q$Strength day. 1x/week, with at least 48h before next hard session. Use heavier of the pair.$q$, $q$Double KB front squat + double press are the two highest-bang KB strength lifts. Low reps, longer rest = real strength adaptation, not just sweat.$q$, 16),
  ($q$kb-emom-conditioning$q$, $q$KB EMOM Conditioning$q$, 30, $q$kb_only$q$, $q$deep$q$, $q$Conditioning day. Use a moderate KB — heavy enough to challenge, light enough that form holds. Skip if heart rate is already elevated from a prior session.$q$, $q$20-min EMOM is the cleanest dose for KB conditioning — you’re forced to pace, and the rotating movements keep no single muscle from blowing up too early.$q$, 17),
  ($q$kb-getup-carry-day$q$, $q$KB Get-Up & Carry Day$q$, 40, $q$kb_only$q$, $q$medium$q$, $q$The "skill" day — between heavy sessions. Lower-back-friendly, builds shoulder stability and grip without crushing the CNS.$q$, $q$Get-ups + asymmetric carries train every stabilizer the swing/squat/press miss. People who skip this day plateau in their main lifts within months.$q$, 18),
  ($q$kb-swing-conditioning$q$, $q$KB Swing Conditioning$q$, 30, $q$kb_only$q$, $q$deep$q$, $q$Pure posterior chain + cardio session. Don’t do the day before deadlifts or heavy lower body.$q$, $q$Heavy swings = best hip-hinge cardio there is. EMOM swings build glute/ham/grip endurance simultaneously while parking heart rate around threshold.$q$, 19),
  ($q$kb-bw-strength-mix$q$, $q$KB + BW Strength Mix$q$, 45, $q$kb_bodyweight$q$, $q$medium$q$, $q$Default hybrid day. Pull-ups carry the upper-back work that KB alone misses — that’s the whole point of pairing them.$q$, $q$KB hammers the loaded patterns; bodyweight (especially pull-ups, push-ups) covers what KB can't. Together = balanced full-body without needing a gym.$q$, 20),
  ($q$kb-bw-circuit$q$, $q$KB + BW Circuit$q$, 35, $q$kb_bodyweight$q$, $q$deep$q$, $q$Conditioning circuit — 4 rounds, minimal rest between exercises (60–90s rest between rounds). Picks up where straight-set days leave off.$q$, $q$Continuous movement across full body keeps heart rate elevated while still working real strength patterns. The goblet/swing/row mix prevents grip from being the limiting factor.$q$, 21),
  ($q$kb-bw-amrap-density$q$, $q$KB + BW AMRAP Density$q$, 25, $q$kb_bodyweight$q$, $q$deep$q$, $q$Short, brutal day. AMRAP format pushes pacing skills — score it, beat it next time. Don’t stack with another conditioning session same week.$q$, $q$Density work (more work in fixed time) is the most efficient way to bridge strength and conditioning. The clean & press anchors it as real loaded work, not just cardio.$q$, 22),
  ($q$kb-bw-core-carries$q$, $q$KB + BW Core & Carries$q$, 35, $q$kb_bodyweight$q$, $q$medium$q$, $q$Active accessory day between heavy sessions. Builds the trunk + grip foundation that carries every lift heavier.$q$, $q$Loaded carries are the most underused tool in fitness — they hit core, traps, grip, and conditioning in one shot. Pair with anti-extension/anti-rotation core and you fix what every desk worker is missing.$q$, 23),
  ($q$kb-bw-athletic-power$q$, $q$KB + BW Athletic Power$q$, 35, $q$kb_bodyweight$q$, $q$deep$q$, $q$Once a week max. Explosive day — needs fresh legs and CNS. Skip if you slept badly or did anything heavy yesterday.$q$, $q$Jumps + KB swings + push-press = triple-extension and explosive output everywhere. This is what keeps you athletic instead of just strong.$q$, 24),
  ($q$gym-compound-5x5$q$, $q$Gym Compound 5×5$q$, 60, $q$gym$q$, $q$deep$q$, $q$The strength anchor of the week. 1–2x/week max, with at least 2 days between. Add weight when you hit all 5×5 with clean form.$q$, $q$Squat, bench, row, RDL, pull-up — five lifts that cover the entire body. 5×5 is the highest-ROI rep scheme for intermediate strength gains. If only one gym day exists, this is it.$q$, 25),
  ($q$gym-heavy-pull-push$q$, $q$Gym Heavy Pull/Push$q$, 65, $q$gym$q$, $q$deep$q$, $q$Heavy day — pairs with the 5×5 day, do them at least 48h apart. Deadlift is the centerpiece, treat it like a real lift.$q$, $q$Deadlift + overhead press are the two lifts the 5×5 day misses. Together those two days cover the full strength matrix at low rep ranges where actual strength is built.$q$, 26),
  ($q$gym-hypertrophy-full-body$q$, $q$Gym Hypertrophy Full Body$q$, 60, $q$gym$q$, $q$medium$q$, $q$Volume day. Slot between the two heavy days — moderate weight, higher reps, less CNS cost. This is where size shows up.$q$, $q$Heavy days build strength; this day builds the muscle. 8–12 rep range with controlled tempo on every major muscle group = the hypertrophy sweet spot.$q$, 27),
  ($q$gym-athletic-conditioning$q$, $q$Gym Athletic Conditioning$q$, 50, $q$gym$q$, $q$deep$q$, $q$Mixed-modal day. Power output + conditioning. Don’t do the day before heavy squat or deadlift — power cleans tax the same systems.$q$, $q$Power cleans + push press build explosive strength the slow lifts miss. Adding sled or rower at the end pushes capacity without grinding joints. The athletic counterbalance to grind days.$q$, 28),
  ($q$gym-lower-focus$q$, $q$Gym Lower Focus + Upper Maintenance$q$, 60, $q$gym$q$, $q$deep$q$, $q$Use as the second leg-heavy day if running 4-day week. Lower body gets the volume; upper body gets just enough to maintain.$q$, $q$Most intermediate lifters under-train legs and over-train chest. This day fixes that — squats + RDLs + lunges hit every part of the lower body, and upper work is kept minimal so legs actually recover and grow.$q$, 29),
  ($q$yael-lower-hip-thrust-strength$q$, $q$Heavy Hip Thrust + Glute Strength$q$, 60, $q$lower_body$q$, $q$deep$q$, $q$The glute strength anchor of the week. 1x/week, with at least 48h before next lower day. Add weight when all sets feel clean.$q$, $q$Heavy hip thrust is the single highest-output lift for glute development — more direct than squats, more loadable than kickbacks. Pair it with Bulgarians and RDLs and you cover every angle the glutes work through.$q$, 30),
  ($q$yael-lower-squat-lunge-volume$q$, $q$Squat & Lunge Volume$q$, 60, $q$lower_body$q$, $q$medium$q$, $q$The hypertrophy lower day. Slot mid-week between heavy hip thrust and posterior chain. Moderate weight, controlled tempo.$q$, $q$Squats + lunges + step-ups hit glutes through full hip flexion under load — the angle hip thrusts miss. Higher reps with shorter rest = the muscle-building sweet spot for legs.$q$, 31),
  ($q$yael-lower-posterior-chain$q$, $q$Posterior Chain & Hamstring$q$, 55, $q$lower_body$q$, $q$deep$q$, $q$The hamstring/posterior day. Use as your second heavy lower session, with at least 48h from hip thrust day. Sumo deadlift is the centerpiece.$q$, $q$Sumo deadlift hits glutes harder than conventional thanks to the wider stance and more upright torso. Pairing it with single-leg RDLs and curls covers every fiber from glute insertion down to knee.$q$, 32),
  ($q$yael-lower-glute-pump$q$, $q$Glute Hypertrophy Pump$q$, 50, $q$lower_body$q$, $q$medium$q$, $q$The "feel-it" day — high-volume, machine + cable focus, less CNS cost. Use between heavy lower days or as your fourth lower session if running 4 leg days.$q$, $q$High-rep cable + machine work nails the glute pump where heavy barbells leave reps on the table. The drop set at the end pushes past failure on muscles that respond well to metabolic stress.$q$, 33),
  ($q$yael-lower-glute-power-plyo$q$, $q$Glute Power & Plyometric$q$, 45, $q$lower_body$q$, $q$deep$q$, $q$The athletic day — once a week max. Needs fresh legs. Pairs explosive jumps with heavy hip thrusts (contrast training). Skip if you slept badly.$q$, $q$Contrast training (heavy strength + explosive plyo back-to-back) recruits more motor units than either does alone. Builds shape AND athleticism — the muscle gets denser, not just bigger.$q$, 34),
  ($q$yael-upper-shoulders-chest$q$, $q$Shoulders & Chest Sculpt$q$, 55, $q$upper_body$q$, $q$medium$q$, $q$The push-focus day. Slot opposite a pull day, with at least 48h between two push sessions. Lateral raises are the priority — they build the "shoulder cap" look.$q$, $q$Lateral and rear delts are the visual difference between flat shoulders and the rounded look. Most women under-train them. Adding moderate chest work keeps the upper body proportional without bulking the pecs.$q$, 35),
  ($q$yael-upper-back-biceps$q$, $q$Back & Biceps Pull Day$q$, 55, $q$upper_body$q$, $q$medium$q$, $q$The pull-focus day. Pair with the push day across the week. Strong back = better posture and the "snatched waist" illusion most women are after.$q$, $q$Wide-grip pulls build the lats (visual taper from waist to shoulder). Rows build mid-back thickness for posture. Face pulls fix rounded shoulders from desk work — the silent killer of upper-body aesthetics.$q$, 36),
  ($q$yael-upper-sculpt-volume$q$, $q$Shoulders & Arms Sculpt$q$, 50, $q$upper_body$q$, $q$medium$q$, $q$The accessory/sculpt day — high reps, cables, drop sets. Slot between heavy push and pull days. Lower CNS cost so it fits anywhere in the week.$q$, $q$Cable + isolation work at high reps maximizes time-under-tension on the small muscles (medial delts, biceps, triceps) that finish the upper-body shape. Drop sets push these muscles past where straight sets can.$q$, 37),
  ($q$yael-upper-superset-volume$q$, $q$Push/Pull Superset Volume$q$, 60, $q$upper_body$q$, $q$medium$q$, $q$The density day — supersets keep heart rate up while still building muscle. Good fat-loss day since it doubles as conditioning. Use later in the week.$q$, $q$Antagonist supersets (push paired with pull) cut total workout time without dropping volume — and the elevated heart rate burns more calories than straight sets. Best of both worlds for muscle gain + fat loss.$q$, 38),
  ($q$yael-upper-strength-circuit$q$, $q$Upper Strength Circuit$q$, 50, $q$upper_body$q$, $q$deep$q$, $q$The lower-rep strength day. Once a week. Real strength work in the 6–8 rep range — push slightly heavier than the volume days.$q$, $q$Most "girl-coded" upper programs live at 12+ reps and never get strong. A weekly heavier session (6–8 reps) is what keeps muscle from plateauing — and progressively heavier weights are the actual driver of body composition change, not just rep count.$q$, 39)
